#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        static char s[100005];
        scanf("%s", s);
        int prev = -1; // previous person's position (1‑based)
        int groups = 0;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') {
                int cur = i + 1;
                if (prev == -1) {
                    groups = 1; // first person creates first group
                } else {
                    if (cur - prev > K + 2) ++groups;
                }
                prev = cur;
            }
        }
        printf("%d\n", groups);
    }
    return 0;
}

