def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        S = next(it).strip()
        prev = -1
        groups = 0
        for i,ch in enumerate(S):
            if ch == '1':
                cur = i+1
                if prev == -1:
                    groups = 1
                elif cur - prev > K + 2:
                    groups += 1
                prev = cur
        out_lines.append(str(groups))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

